  ('bookkeeper-moex-01449', 'bookkeeper', 'bookkeeper-moex-103-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '主辦會計違反我國最新修正商業會計法第25條規定，不設置應備之會計帳簿目錄，依同法第79條規定，應 依下列那一項處罰？', '["新臺幣一萬元以上五萬元以下罰鍰", "新臺幣三萬元以上十五萬元以下罰鍰", "新臺幣六萬元以上三十萬元以下罰鍰", "新臺幣十萬元以上罰金"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "f10e4f0a1f1e", "answer_pdf_sha1": "c42dc131ca03", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01450', 'bookkeeper', 'bookkeeper-moex-103-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '依據我國行政程序法之規定，處分機關告知之救濟期間有錯誤時，應由該機關以通知更正之，並自何時起算 法定期間？', '["通知送達之日起算", "通知送達之翌日起算", "通知送達十日後起算", "通知送達三十日後起算"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "f10e4f0a1f1e", "answer_pdf_sha1": "c42dc131ca03", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01451', 'bookkeeper', 'bookkeeper-moex-103-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '依據我國行政程序法之規定，下列有關行政處分之敘述何者錯誤？', '["行政處分係指行政機關就公法上具體事件所為之決定或其他公權力措施，而對外直接發生法律效果之單方 行政行為", "行政機關作成行政處分有裁量權時，得為附款，如期限、條件等", "行政處分得以書面、言詞或其他方式為之", "以書面以外方式所為之行政處分，其相對人或利害關係人不得要求作成書面處分"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "f10e4f0a1f1e", "answer_pdf_sha1": "c42dc131ca03", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01452', 'bookkeeper', 'bookkeeper-moex-103-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '依據我國行政程序法之規定，對於行政處分聲明不服，因處分機關未為告知或告知錯誤致向無管轄權之機關 為之者，該機關應於幾日內移送有管轄權之機關，並通知當事人？', '["三日內", "十日內", "二十日內", "三十日內"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "f10e4f0a1f1e", "answer_pdf_sha1": "c42dc131ca03", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01453', 'bookkeeper', 'bookkeeper-moex-103-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '依據我國行政程序法之規定，下列有關行政處分撤銷之敘述何者錯誤？', '["違法行政處分於法定救濟期間經過後即不得撤銷", "違法行政處分於法定救濟期間經過後，原處分機關得依職權為全部或一部之撤銷", "撤銷對公益有重大危害者，不得撤銷", "受益人無行政程序法第119條所列信賴不值得保護之情形，而信賴授予利益之行政處分，其信賴利益顯然 大於撤銷所欲維護之公益者，不得撤銷"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "f10e4f0a1f1e", "answer_pdf_sha1": "c42dc131ca03", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01454', 'bookkeeper', 'bookkeeper-moex-103-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '依行政程序法第131條規定，公法上之請求權，於請求權人為行政機關時，除法律另有規定外，因幾年間不 行使而消滅？', '["十年", "七年", "五年", "三年"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "f10e4f0a1f1e", "answer_pdf_sha1": "c42dc131ca03", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01455', 'bookkeeper', 'bookkeeper-moex-103-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '依行政程序法第112條規定，行政處分一部分無效者，其他部分仍為有效。但除去該無效部分，行政處分不 能成立者，其效力為何？', '["全部無效", "部分無效", "全部有效", "部分有效"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "f10e4f0a1f1e", "answer_pdf_sha1": "c42dc131ca03", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01456', 'bookkeeper', 'bookkeeper-moex-103-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '依據我國公司法之規定，下列敘述何者錯誤？', '["無限公司係指二人以上股東所組織，對公司債務負連帶無限清償責任之公司", "兩合公司係指一人以上無限責任股東，與一人以上有限責任股東所組織，其無限責任股東對公司債務負連 帶無限清償責任；有限責任股東就其出資額為限，對公司負其責任之公司", "有限公司係指由二人以上股東所組織，就其出資額為限，對公司負其責任之公司", "股份有限公司係指二人以上股東或政府、法人股東一人所組織，全部資本分為股份；股東就其所認股份， 對公司負其責任之公司"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "f10e4f0a1f1e", "answer_pdf_sha1": "c42dc131ca03", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01457', 'bookkeeper', 'bookkeeper-moex-103-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '依公司法第13條規定，一家非以投資為專業之公司，實收股本為1,000萬元，淨值為1,200萬元，如為他公 司有限責任股東時，原則上（排除其他例外相關規定）其所有投資總額上限為多少？', '["400萬元", "480萬元", "500萬元", "600萬元"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "f10e4f0a1f1e", "answer_pdf_sha1": "c42dc131ca03", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "602", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
